// Models/RoutePermission.cs // Новая модель: связывает маршрут (путь) с правом доступа и иконкой для меню  using System.ComponentModel.DataAnnotations.Schema; // Для атрибутов ORM using System.ComponentModel.DataAnnotations;       // Для Data Annotations (например, Key)  namespace MES_ME.Server.Models {     [Table("route_permissions")] // Указывает имя таблицы и схемы     public class RoutePermission     {         [Column("id")]         public int Id { get; set; }         [Column("path")]         // Путь маршрута, например "/sheet-accounting"         public string Path { get; set; } = null!;         [Column("label")]         // Отображаемое название в меню         public string Label { get; set; } = null!;                  [Column("icon_name")]         // Название иконки MUI (строка, например "Assignment", "People")         public string IconName { get; set; } = "Dashboard";         [Column("sort_order")]         // Порядок отображения в сайдбаре         public int SortOrder { get; set; } = 0;         [Column("required_permission")]         // Право, необходимое для доступа к маршруту (ссылка на Permission.Name)         public string RequiredPermission { get; set; } = null!;                 [Column("is_active")]         // Активен ли маршрут (можно скрыть без удаления)          public bool IsActive { get; set; } = true;     } } 